sql:
SELECT COUNT(DISTINCT a.entry_id) AS viewed_proteins
FROM access_logs a
WHERE a.action = 'view' AND strftime('%Y', a.access_date) = '2022';

SELECT COUNT(*) AS total_proteins, AVG(length) AS average_length
FROM proteins
WHERE status = 'unreviewed' AND organism = 'Oryza sativa subsp. japonica (Rice)';

SELECT entry_id
FROM proteins
WHERE status = 'reviewed' AND is_active = 1 AND organism = 'Escherichia coli';

SELECT researchers.researcher_name, access_logs.access_date
FROM researchers
INNER JOIN access_logs ON researchers.researcher_id = access_logs.researcher_id;
